nditions.checkState(input.isExtern(), "Not an extern input: %s", input.getName());    inputsById.remove(id);    externs.remove(input);    Node root = input.getAstRoot(this);    if (root != null) {      root.detachFromParent();    }  }  @Override  public CompilerInput newExternInput(String name) {    SourceAst ast = new SyntheticAst(name);    if (inputsById.containsKey(ast.getInputId())) {      throw new IllegalArgumentException("Conflicting externs name: " + name);    }    CompilerInput input = new CompilerInput(ast, true);    inputsById.put(input.getInputId(), input);    externsRoot.addChildToFront(ast.getAstRoot(this));    externs.add(0, input);    return input;  }  /** Add a source input dynamically. Intended for incremental compilation. */  void addIncrementalSourceAst(JsAst ast) {    InputId id = ast.getInputId();    Preconditions.checkState(getInput(id) == null, "Duplicate input %s", id.getIdName());    inputsById.put(id, new CompilerInput(ast));  }  /**   * Replace a source input dynamically. Intended for incremental   * re-compilation.   *   * If the new source input doesn't parse, then keep the old input   * in the AST and return false.   *   * @return Whether the new AST was attached successfully.   */  boolean replaceIncrementalSourceAst(JsAst ast) {    CompilerInput oldInput = getInput(ast.getInputId());    Preconditions.checkNotNull(oldInput, "No input to replace: %s", ast.getInputId().getIdName());    Node newRoot = ast.getAstRoot(this);    if (newRoot == null) {      return false;    }    Node oldRoot = oldInput.getAstRoot(this);    if (oldRoot != null) {      oldRoot.getParent().replaceChild(oldRoot, newRoot);    } else {      getRoot().getLastChild().addChildToBack(newRoot);    }    CompilerInput newInput = new CompilerInput(ast);    inputsById.put(ast.getInputId(), newInput);    JSModule module = oldInput.getModule();    if (module != null) {      module.addAfter(newInput, oldInput);      module.remove(oldInput);    }    // Verify the input id is set properly.    Preconditions.checkState(        newInput.getInputId().equals(oldInput.getInputId()));    InputId inputIdOnAst = newInput.getAstRoot(this).getInputId();    Preconditions.checkState(newInput.getInputId().equals(inputIdOnAst));    inputs.remove(oldInput);    return true;  }  /**   * Add a new source input dynamically. Intended for incremental compilation.   * <p>   * If the new source input doesn't parse, it will not be added, and a false   * will be returned.   *   * @param ast the JS Source to add.   * @return true if the source was added successfully, false otherwise.   * @throws IllegalStateException if an input for this ast already exists.   */  boolean addNewSourceAst(JsAst ast) {    CompilerInput oldInput = getInput(ast.getInputId());    if (oldInput != null) {      throw new IllegalStateException(          "Input already exists: " + ast.getInputId().getIdName());    }    Node newRoot = ast.getAstRoot(this);    if (newRoot == null) {      return false;    }    getRoot().getLastChild().addChildToBack(newRoot);    CompilerInput newInput = new CompilerInput(ast);    // TODO(tylerg): handle this for multiple modules at some point.    if (moduleGraph == null && !modules.isEmpty()) {      // singleton module      modules.get(0).add(newInput);    }    inputsById.put(ast.getInputId(), newInput);    return true;  }  @Override  JSModuleGraph getModuleGraph() {    return moduleGraph;  }  @Override  public JSTypeRegistry getTypeRegistry() {    if (typeRegistry == null) {      typeRegistry = new JSTypeRegistry(oldErrorReporter, options.looseTypes);    }    return typeRegistry;  }  @Override  MemoizedScopeCreator getTypedScopeCreator() {    return getPassConfig().getTypedScopeCreator();  }  @SuppressWarnings("unchecked")  DefaultPassConfig ensureDefaultPassConfig() {    PassConfig passes = getPassConfig().getBasePassConfig();    Preconditions.checkState(passes instanceof DefaultPassConfig,        "PassConfigs must eventually delegate to the DefaultPassConfig");    return (DefaultPassConfig) passes;  }  public SymbolTable buildKnownSymbolTable() {    SymbolTable symbolTable = new SymbolTable(getTypeRegistry());    MemoizedScopeCreator typedScopeCreator = getTypedScopeCreator();    if (typedScopeCreator != null) {      symbolTable.addScopes(typedScopeCreator.getAllMemoizedScopes());      symbolTable.addSymbolsFrom(typedScopeCreator);    } else {      symbolTable.findScopes(this, externsRoot, jsRoot);    }    GlobalNamespace globalNamespace =        ensureDefaultPassConfig().getGlobalNamespace();    if (globalNamespace != null) {      symbolTable.addSymbolsFrom(globalNamespace);    }    ReferenceCollectingCallback refCollector =        new ReferenceCollectingCallback(            this, ReferenceCollectingCallback.DO_NOTHING_BEHAVIOR);    NodeTraversal.traverse(this, getRoot(), refCollector);    symbolTable.addSymbolsFrom(refCollector);    PreprocessorSymbolTable preprocessorSymbolTable =        ensureDefaultPassConfig().getPreprocessorSymbolTable();    if (preprocessorSymbolTable != null) {      symbolTable.addSymbolsFrom(preprocessorSymbolTable);    }    symbolTable.fillNamespaceReferences();    symbolTable.fillPropertyScopes();    symbolTable.fillThisReferences(this, externsRoot, jsRoot);    symbolTable.fillPropertySymbols(this, externsRoot, jsRoot);    symbolTable.fillJSDocInfo(this, externsRoot, jsRoot);    return symbolTable;  }  @Override  public Scope getTopScope() {    return getPassConfig().getTopScope();  }  @Override  public ReverseAbstractInterpreter getReverseAbstractInterpreter() {    if (abstractInterpreter == null) {      ChainableReverseAbstractInterpreter interpreter =          new SemanticReverseAbstractInterpreter(              getCodingConvention(), getTypeRegistry());      if (options.closurePass) {        interpreter = new ClosureReverseAbstractInterpreter(            getCodingConvention(), getTypeRegistry())            .append(interpreter).getFirst();      }      abstractInterpreter = interpreter;    }    return abstractInterpreter;  }  @Override  TypeValidator getTypeValidator() {    if (typeValidator == null) {      typeValidator = new TypeValidator(this);    }    return typeValidator;  }  //------------------------------------------------------------------------  // Parsing  //------------------------------------------------------------------------  /**   * Parses the externs and main inputs.   *   * @return A synthetic root node whose two children are the externs root   *     and the main root   */  Node parseInputs() {    boolean devMode = options.devMode != DevMode.OFF;    // If old roots exist (we are parsing a second time), detach each of the    // individual file parse trees.    if (externsRoot != null) {      externsRoot.detachChildren();    }    if (jsRoot != null) {      jsRoot.detachChildren();    }    // Parse main js sources.    jsRoot = IR.block();    jsRoot.setIsSyntheticBlock(true);    externsRoot = IR.block();    externsRoot.setIsSyntheticBlock(true);    externAndJsRoot = IR.block(externsRoot, jsRoot);    externAndJsRoot.setIsSyntheticBlock(true);    if (options.tracer.isOn()) {      tracker = new PerformanceTracker(jsRoot,          options.tracer == TracerMode.ALL);      addChangeHandler(tracker.getCodeChangeHandler());    }    Tracer tracer = newTracer("parseInputs");    try {      // Parse externs sources.      for (CompilerInput input : externs) {        Node n = input.getAstRoot(this);        if (hasErrors()) {          return null;        }        externsRoot.addChildToBack(n);      }      // Modules inferred in ProcessCommonJS pass.      if (options.transformAMDToCJSModules || options.processCommonJSModules) {        processAMDAndCommonJSModules();      }      // Check if the sources need to be re-ordered.      if (options.dependencyOptions.needsManagement()) {        for (CompilerInput input : inputs) {          input.setCompiler(this);          // Forward-declare all the provided types, so that they          // are not flagged even if they are dropped from the process.          for (String provide : input.getProvides()) {            getTypeRegistry().forwardDeclareType(provide);          }        }        try {          inputs =              (moduleGraph == null ? new JSModuleGraph(modules) : moduleGraph)              .manageDependencies(options.dependencyOptions, inputs);        } catch (CircularDependencyException e) {          report(JSError.make(              JSModule.CIRCULAR_DEPENDENCY_ERROR, e.getMessage()));          // If in IDE mode, we ignore the error and keep going.          if (hasErrors()) {            return null;          }        } catch (MissingProvideException e) {          report(JSError.make(              MISSING_ENTRY_ERROR, e.getMessage()));          // If in IDE mode, we ignore the error and keep going.          if (hasErrors()) {            return null;          }        }      }      // Check if inputs need to be rebuilt from modules.      boolean staleInputs = false;      for (CompilerInput input : inputs) {        Node n = input.getAstRoot(this);        // Inputs can have a null AST during initial parse.        if (n == null) {          continue;        }        if (n.getJSDocInfo() != null) {          JSDocInfo info = n.getJSDocInfo();          if (info.isExterns()) {            // If the input file is explicitly marked as an externs file, then            // assume the programmer made a mistake and throw it into            // the externs pile anyways.            externsRoot.addChildToBack(n);            input.setIsExtern(true);            input.getModule().remove(input);            externs.add(input);            staleInputs = true;          } else if (info.isNoCompile()) {            input.getModule().remove(input);            staleInputs = true;          }        }      }      if (staleInputs) {        fillEmptyModules(modules);        rebuildInputsFromModules();      }      // Build the AST.      for (CompilerInput input : inputs) {        Node n = input.getAstRoot(this);        if (n == null) {          continue;        }        if (devMode) {          runSanityCheck();          if (hasErrors()) {            return null;          }        }        if (options.sourceMapOutputPath != null ||            options.nameReferenceReportPath != null) {          // Annotate the nodes in the tree with information from the          // input file. This information is used to construct the SourceMap.          SourceInformationAnnotator sia =              new SourceInformationAnnotator(                  input.getName(), options.devMode != DevMode.OFF);          NodeTraversal.traverse(this, n, sia);        }        jsRoot.addChildToBack(n);      }      if (hasErrors()) {        return null;      }      return externAndJsRoot;    } finally {      stopTracer(tracer, "parseInputs");    }  }  /**   * Transforms AMD and CJS modules to something closure compiler can   * process and creates JSModules and the corresponding dependency tree   * on the way.   */  private void processAMDAndCommonJSModules() {    Map<String, JSModule> modulesByName = Maps.newLinkedHashMap();    Map<CompilerInput, JSModule> modulesByInput = Maps.newLinkedHashMap();    // TODO(nicksantos): Refactor module dependency resolution to work nicely    // with multiple ways to express dependencies. Directly support JSModules    // that are equivalent to a signal file and which express their deps    // directly in the source.    for (CompilerInput input : inputs) {      input.setCompiler(this);      Node root = input.getAstRoot(this);      if (root == null) {        continue;      }      if (options.transformAMDToCJSModules) {        new TransformAMDToCJSModule(this).process(null, root);      }      if (options.processCommonJSModules) {        ProcessCommonJSModules cjs = new ProcessCommonJSModules(this,            options.commonJSModulePathPrefix);        cjs.process(null, root);        JSModule m = cjs.getModule();        if (m != null) {          modulesByName.put(m.getName(), m);          modulesByInput.put(input, m);        }      }    }    if (options.processCommonJSModules) {      List<JSModule> modules = Lists.newArrayList(modulesByName.values());      if (!modules.isEmpty()) {        this.modules = modules;        this.moduleGraph = new JSModuleGraph(this.modules);      }      for (JSModule module : modules) {        for (CompilerInput input : module.getInputs()) {          for (String require : input.getRequires()) {            module.addDependency(modulesByName.get(require));          }        }      }      try {        modules = Lists.newArrayList();        for (CompilerInput input : this.moduleGraph.manageDependencies(            options.dependencyOptions, inputs)) {          modules.add(modulesByInput.get(input));        }        this.modules = modules;        this.moduleGraph = new JSModuleGraph(modules);      } catch (Exception e) {        Throwables.propagate(e);      }    }  }  public Node parse(JSSourceFile file) {    initCompilerOptionsIfTesting();    addToDebugLog("Parsing: " + file.getName());    return new JsAst(file).getAstRoot(this);  }  private int syntheticCodeId = 0;  @Override  Node parseSyntheticCode(String js) {    CompilerInput input = new CompilerInput(        JSSourceFile.fromCode(" [synthetic:" + (++syntheticCodeId) + "] ", js));    inputsById.put(input.getInputId(), input);    return input.getAstRoot(this);  }  /**   * Allow subclasses to override the default CompileOptions object.   */  protected CompilerOptions newCompilerOptions() {    return new CompilerOptions();  }  void initCompilerOptionsIfTesting() {    if (options == null) {      // initialization for tests that don't initialize the compiler      // by the normal mechanisms.      initOptions(newCompilerOptions());    }  }  @Override  Node parseSyntheticCode(String fileName, String js) {    initCompilerOptionsIfTesting();    return parse(JSSourceFile.fromCode(fileName, js));  }  @Override  Node parseTestCode(String js) {    initCompilerOptionsIfTesting();    CompilerInput input = new CompilerInput(        JSSourceFile.fromCode(" [testcode] ", js));    if (inputsById == null) {      inputsById = Maps.newHashMap();    }    inputsById.put(input.getInputId(), input);    return input.getAstRoot(this);  }  @Override  ErrorReporter getDefaultErrorReporter() {    return defaultErrorReporter;  }  //------------------------------------------------------------------------  // Convert back to source code  //------------------------------------------------------------------------  /**   * Converts the main parse tree back to js code.   */  public String toSource() {    return runInCompilerThread(new Callable<String>() {      @Override      public String call() throws Exception {        Tracer tracer = newTracer("toSource");        try {          CodeBuilder cb = new CodeBuilder();          if (jsRoot != null) {            int i = 0;            for (Node scriptNode = jsRoot.getFirstChild();                 scriptNode != null;                 scriptNode = scriptNode.getNext()) {              toSource(cb, i++, scriptNode);            }          }          return cb.toString();        } finally {          stopTracer(tracer, "toSource");        }      }    });  }  /**   * Converts the parse tree for each input back to js code.   */  public String[] toSourceArray() {    return runInCompilerThread(new Callable<String[]>() {      @Override      public String[] call() throws Exception {        Tracer tracer = newTracer("toSourceArray");        try {          int numInputs = inputs.size();          String[] sources = new String[numInputs];          CodeBuilder cb = new CodeBuilder();          for (int i = 0; i < numInputs; i++) {            Node scriptNode = inputs.get(i).getAstRoot(Compiler.this);            cb.reset();            toSource(cb, i, scriptNode);            sources[i] = cb.toString();          }          return sources;        } finally {          stopTracer(tracer, "toSourceArray");        }      }    });  }  /**   * Converts the parse tree for a module back to js code.   */  public String toSource(final JSModule module) {    return runInCompilerThread(new Callable<String>() {      @Override      public String call() throws Exception {        List<CompilerInput> inputs = module.getInputs();        int numInputs = inputs.size();        if (numInputs == 0) {          return "";        }        CodeBuilder cb = new CodeBuilder();        for (int i = 0; i < numInputs; i++) {          Node scriptNode = inputs.get(i).getAstRoot(Compiler.this);          if (scriptNode == null) {            throw new IllegalArgumentException(                "Bad module: " + module.getName());          }          toSource(cb, i, scriptNode);        }        return cb.toString();      }    });  }  /**   * Converts the parse tree for each input in a module back to js code.   */  public String[] toSourceArray(final JSModule module) {    return runInCompilerThread(new Callable<String[]>() {      @Override      public String[] call() throws Exception {        List<CompilerInput> inputs = module.getInputs();        int numInputs = inputs.size();        if (numInputs == 0) {          return new String[0];        }        String[] sources = new String[numInputs];        CodeBuilder cb = new CodeBuilder();        for (int i = 0; i < numInputs; i++) {          Node scriptNode = inputs.get(i).getAstRoot(Compiler.this);          if (scriptNode == null) {            throw new IllegalArgumentException(                "Bad module input: " + inputs.get(i).getName());          }          cb.reset();          toSource(cb, i, scriptNode);          sources[i] = cb.toString();        }        return sources;      }    });  }  /**   * Writes out js code from a root node. If printing input delimiters, this   * method will attach a comment to the start of the text indicating which   * input the output derived from. If there were any preserve annotations   * within the root's source, they will also be printed in a block comment   * at the beginning of the output.   */  public void toSource(final CodeBuilder cb,                       final int inputSeqNum,                       final Node root) {    runInCompilerThread(new Callable<Void>() {      @Override      public Void call() throws Exception {        if (options.printInputDelimiter) {          if ((cb.getLength() > 0) && !cb.endsWith("\n")) {            cb.append("\n");  // Make sure that the label starts on a new line          }          Preconditions.checkState(root.isScript());          String delimiter = options.inputDelimiter;          String inputName = root.getInputId().getIdName();          String sourceName = root.getSourceFileName();          Preconditions.checkState(sourceName != null);          Preconditions.checkState(!sourceName.isEmpty());          delimiter = delimiter              .replaceAll("%name%", Matcher.quoteReplacement(inputName))              .replaceAll("%num%", String.valueOf(inputSeqNum));          cb.append(delimiter)            .append("\n");        }        if (root.getJSDocInfo() != null &&            root.getJSDocInfo().getLicense() != null) {          cb.append("/*\n")            .append(root.getJSDocInfo().getLicense())            .append("*/\n");        }        // If there is a valid source map, then indicate to it that the current        // root node's mappings are offset by the given string builder buffer.        if (options.sourceMapOutputPath != null) {          sourceMap.setStartingPosition(              cb.getLineIndex(), cb.getColumnIndex());        }        // if LanguageMode is ECMASCRIPT5_STRICT, only print 'use strict'        // for the first input file        String code = toSource(root, sourceMap, inputSeqNum == 0);        if (!code.isEmpty()) {          cb.append(code);          // In order to avoid parse ambiguity when files are concatenated          // together, all files should end in a semi-colon. Do a quick          // heuristic check if there's an obvious semi-colon already there.          int length = code.length();          char lastChar = code.charAt(length - 1);          char secondLastChar = length >= 2 ?              code.charAt(length - 2) : '\0';          boolean hasSemiColon = lastChar == ';' ||              (lastChar == '\n' && secondLastChar == ';');          if (!hasSemiColon) {            cb.append(";");          }        }        return null;      }    });  }  /**   * Generates JavaScript source code for an AST, doesn't generate source   * map info.   */  @Override  String toSource(Node n) {    initCompilerOptionsIfTesting();    return toSource(n, null, true);  }  /**   * Generates JavaScript source code for an AST.   */  private String toSource(Node n, SourceMap sourceMap, boolean firstOutput) {    CodePrinter.Builder builder = new CodePrinter.Builder(n);    builder.setPrettyPrint(options.prettyPrint);    builder.setLineBreak(options.lineBreak);    builder.setSourceMap(sourceMap);    builder.setSourceMapDetailLevel(options.sourceMapDetailLevel);    builder.setTagAsStrict(firstOutput &&        options.getLanguageOut() == LanguageMode.ECMASCRIPT5_STRICT);    builder.setLineLengthThreshold(options.lineLengthThreshold);    Charset charset = options.outputCharset != null ?        Charset.forName(options.outputCharset) : null;    builder.setOutputCharset(charset);    return builder.build();  }  /**   * Stores a buffer of text to which more can be appended.  This is just like a   * StringBuilder except that we also track the number of lines.   */  public static class CodeBuilder {    private final StringBuilder sb = new StringBuilder();    private int lineCount = 0;    private int colCount = 0;    /** Removes all text, but leaves the line count unchanged. */    void reset() {      sb.setLength(0);    }    /** Appends the given string to the text buffer. */    CodeBuilder append(String str) {      sb.append(str);      // Adjust the line and column information for the new text.      int index = -1;      int lastIndex = index;      while ((index = str.indexOf('\n', index + 1)) >= 0) {        ++lineCount;        lastIndex = index;      }      if (lastIndex == -1) {        // No new lines, append the new characters added.        colCount += str.length();      } else {        colCount = str.length() - (lastIndex + 1);      }      return this;    }    /** Returns all text in the text buffer. */    @Override    public String toString() {      return sb.toString();    }    /** Returns the length of the text buffer. */    public int getLength() {      return sb.length();    }    /** Returns the (zero-based) index of the last line in the text buffer. */    int getLineIndex() {      return lineCount;    }    /** Returns the (zero-based) index of the last column in the text buffer. */    int getColumnIndex() {      return colCount;    }    /** Determines whether the text ends with the given suffix. */    boolean endsWith(String suffix) {      return (sb.length() > suffix.length())          && suffix.equals(sb.substring(sb.length() - suffix.length()));    }  }  //------------------------------------------------------------------------  // Optimizations  //------------------------------------------------------------------------  public void optimize() {    // Ideally, this pass should be the first pass run, however:    // 1) VariableReferenceCheck reports unexpected warnings if Normalize    // is done first.    // 2) ReplaceMessages, stripCode, and potentially custom passes rely on    // unmodified local names.    normalize();    PhaseOptimizer phaseOptimizer = new PhaseOptimizer(this, tracker);    if (options.devMode == DevMode.EVERY_PASS) {      phaseOptimizer.setSanityCheck(sanityCheck);    }    phaseOptimizer.consume(getPassConfig().getOptimizations());    phaseOptimizer.process(externsRoot, jsRoot);    if (hasErrors()) {      return;    }  }  @Override  void setCssRenamingMap(CssRenamingMap map) {    options.cssRenamingMap = map;  }  @Override  CssRenamingMap getCssRenamingMap() {    return options.